public void rollback()
    {
        // Rollback all soft resources.
        for (Transactional enlist : enlists)
        {
            enlist.rollback();
        }

        // Clear all of the rolled back resources.
        enlists.clear();

        // Invalidate the transaction id, so that a fresh transaction is begun.
