private String makeName(char[] buff, int offset, int length) {
        StringBuffer dst = new StringBuffer(length + 2);
        boolean seenColon = false;
        boolean start = true;
        // String src = new String(buff, offset, length); // DEBUG
        for (; length-- > 0; offset++) {
            char ch = buff[offset];
            if (Character.isLetter(ch) || ch == '_') {
                start = false;
                dst.append(ch);
            } else if (Character.isDigit(ch) || ch == '-' || ch == '.') {
                if (start)
                    dst.append('_');
                start = false;
                dst.append(ch);
            } else if (ch == ':' && !seenColon) {
                seenColon = true;
                if (start)
                    dst.append('_');
                start = true;
                dst.append(translateColons ? '_' : ch);
            }
        }
        int dstLength = dst.length();
        if (dstLength == 0 || dst.charAt(dstLength - 1) == ':')
            dst.append('_');
        return dst.toString().intern();
    }

public void shutdown(boolean closeDb, boolean commitTx) {
    makeActive();

    try {
      if (!isClosed()) {
        if (commitTx) {
          final OStorage storage = getDatabase().getStorage().getUnderlying();
          if (storage instanceof OAbstractPaginatedStorage) {
            if (((OAbstractPaginatedStorage) storage).getWALInstance() != null)
              getDatabase().commit();
          } else {
            getDatabase().commit();
          }
        } else if (closeDb) {
          getDatabase().rollback();
        }
      }

    } catch (ONeedRetryException e) {
      throw e;
    } catch (RuntimeException e) {
      OLogManager.instance().error(this, "Error during context close for db " + url, e);
      throw e;
    } catch (Exception e) {
      OLogManager.instance().error(this, "Error during context close for db " + url, e);
      throw OException.wrapException(new ODatabaseException("Error during context close for db " + url), e);
    } finally {
      try {
        if (closeDb) {
          getDatabase().close();
          if (getDatabase().isPooled()) {
            database = null;
          }
        }
        pollGraphFromStack(closeDb);
      } catch (Exception e) {
        OLogManager.instance().error(this, "Error during context close for db " + url, e);
      }
    }

    url = null;
    username = null;
    password = null;

    if (!closeDb)
      getDatabase().activateOnCurrentThread();
  }

