private static String xmlAttribEncodeBinary(String value) {
        StringBuilder s = new StringBuilder();
        char buf[] = value.toCharArray();
        for (char c : buf) {
            switch (c) {
            case '<':
                s.append("&lt;");
                break;
            case '>':
                s.append("&gt;");
                break;
            case '&':
                s.append("&amp;");
                break;
            case '"':
                s.append("&quot;");
                break;
            case '\'':
                s.append("&apos;");
                break;
            default:
                if (c <= 0x1f || (0x7f <= c && c <= 0x9f)) { // includes \t, \n,
                                                             // \r
                    s.append("&#x");
                    s.append(String.format("%X", (int) c));
                    s.append(';');
                } else {
                    s.append(c);
                }
            }
        }
        return s.toString();
    }

